const body = $json.body || $json;
const formId = body.form_id;
const formName = body.form_name || null;
const dateFrom = body.date_from;
const dateTo = body.date_to;
const limit = Number(body.limit || 5);

if (!formId || !dateFrom || !dateTo) {
  throw new Error('form_id, date_from, and date_to are required');
}

const query = `type:ticket ticket_form_id:${formId} created>${dateFrom} created<${dateTo} custom_field_1260824167549:support_`;

return [{
  json: {
    form_id: formId,
    form_name: formName,
    date_from: dateFrom,
    date_to: dateTo,
    limit,
    zendesk_query: query
  }
}];

const req = $('Prepare Preview Request').first().json;
const res = $json;
return [{ json: { source: 'zendesk', filters: { form_id: req.form_id, form_name: req.form_name, date_from: req.date_from, date_to: req.date_to, query_used: req.zendesk_query }, total_found: res.count ?? 0 } }];

const data = $getWorkflowStaticData('global');
data.users_pages_loaded = 0;
data.users_rows_loaded = 0;
return [{ json: { url: 'https://kipuhealth.zendesk.com/api/v2/users.json?role[]=agent&page=1&per_page=100' } }];

const data = $getWorkflowStaticData('global');
const body = $('Fetch Users Page').first().json;
const rowCount = $('Pack User Rows JSON').first().json.row_count || 0;
data.users_pages_loaded = (data.users_pages_loaded || 0) + 1;
data.users_rows_loaded = (data.users_rows_loaded || 0) + rowCount;
return [{ json: { next_page: body.next_page || null, page_row_count: rowCount, pages_loaded: data.users_pages_loaded, total_rows_loaded: data.users_rows_loaded, end_of_stream: !body.next_page } }];

const body = $json.body || $json || {};

const data = $getWorkflowStaticData('global');
data.sync_pages_loaded = 0;
data.sync_input_rows = 0;
data.sync_upserted_rows = 0;
data.sync_refreshed_form_rows = 0;
data.sync_refreshed_agent_rows = 0;

const formId = body.form_id;
const formName = body.form_name || null;
const dateFrom = body.date_from;
const dateTo = body.date_to;

if (!formId || !dateFrom || !dateTo) {
  throw new Error('form_id, date_from, and date_to are required');
}

const zendeskQuery = `type:ticket ticket_form_id:${formId} created>${dateFrom} created<${dateTo} custom_field_1260824167549:support_`;

const url = `https://kipuhealth.zendesk.com/api/v2/search.json?query=${encodeURIComponent(zendeskQuery)}&page=1&per_page=100&sort_by=created_at&sort_order=asc`;

return [{
  json: {
    form_id: formId,
    form_name: formName,
    date_from: dateFrom,
    date_to: dateTo,
    zendesk_query: zendeskQuery,
    url
  }
}];

const req = $('Code - Prepare Run Sync Search').first().json || {};
const body = $('Webhook - Run Sync').first().json.body || $('Webhook - Run Sync').first().json || {};
const results = Array.isArray($json.results) ? $json.results : [];
const ticketIds = results.map(r => r.id).filter(id => id != null);

const data = $getWorkflowStaticData('global');
const currentPage = (data.sync_pages_loaded || 0) + 1;  // increments each loop via Code - Accumulate Sync Totals

const totalPages = Math.ceil(($json.count || 0) / 100);  // count = total from Zendesk search

const runId =
  body.run_id ||
  `ticket-sync-${new Date().toISOString().replace(/[:.]/g, '-')}`;

return [{
  json: {
    run_id: runId,
    current_batch: currentPage,
    total_batches: totalPages,
    expected_count: ticketIds.length,
    form_id: req.form_id,
    form_name: req.form_name,
    date_from: req.date_from,
    date_to: req.date_to,
    zendesk_query: req.zendesk_query,
    ticket_ids: ticketIds,
    ids_csv: ticketIds.join(','),
    batch_count: ticketIds.length,
    total_found: $json.count ?? 0,
    next_page_url: $json.next_page || null,
    end_of_stream: !$json.next_page
  }
}];

const batch = $('Code - Prepare Batch IDs').first().json || {};
const tickets = Array.isArray($json.tickets) ? $json.tickets : [];

return tickets.map(ticket => ({
  json: {
    ticket,
    form_name: batch.form_name ?? null
  }
}));

const body = $('Webhook - Run Sync').first().json.body || $('Webhook - Run Sync').first().json || {};
const data = $getWorkflowStaticData('global');

const searchItems = $('HTTP - Search Tickets Page').all();

let totalFound = 0;
for (const item of searchItems) {
  if (item.json?.count != null) {
    totalFound = Number(item.json.count);
    break;
  }
}

const totalBatches = Math.ceil(totalFound / 100);

return [{
  json: {
    status: 'success',
    run_id: body.run_id || null,
    form_id: body.form_id ?? null,
    form_name: body.form_name ?? null,
    date_from: body.date_from ?? null,
    date_to: body.date_to ?? null,
    total_found: totalFound,
    total_batches: totalBatches,
    pages_loaded: data.sync_pages_loaded || 0,
    input_rows: data.sync_input_rows || 0,
    upserted_rows: data.sync_upserted_rows || 0
  }
}];

const batch = $('Code - Prepare Batch IDs').first().json || {};

const tickets = Array.isArray($('HTTP - Fetch Ticket Batch').first().json.tickets)
  ? $('HTTP - Fetch Ticket Batch').first().json.tickets
  : [];

const metricItems = $('HTTP - Fetch Ticket Metrics').all();

const metricsByTicketId = {};
for (const item of metricItems) {
  const metric = item.json?.ticket_metric || {};
  if (metric.ticket_id != null) {
    metricsByTicketId[String(metric.ticket_id)] = metric;
  }
}

const formName = batch.form_name ?? null;

const ARTICLE_LINKED_FIELD_IDS = [18158428639387, 25171038337691];

function getCustomFieldValue(ticket, fieldIds) {
  const fields = Array.isArray(ticket.custom_fields) ? ticket.custom_fields : [];
  for (const fieldId of fieldIds) {
    const match = fields.find(f => Number(f.id) === Number(fieldId));
    if (match && match.value !== undefined && match.value !== null && match.value !== '') {
      return match.value;
    }
  }
  return null;
}

function hasAnyTag(ticket, tagList) {
  const tags = Array.isArray(ticket.tags) ? ticket.tags : [];
  return tagList.some(tag => tags.includes(tag));
}

function normalizeBoolean(value, trueValues = [], falseValues = []) {
  if (value === true) return true;
  if (value === false) return false;
  if (value == null) return null;
  const v = String(value).toLowerCase().trim();
  if (['yes', 'true', '1'].includes(v)) return true;
  if (['no', 'false', '0'].includes(v)) return false;
  if (trueValues.map(x => String(x).toLowerCase()).includes(v)) return true;
  if (falseValues.map(x => String(x).toLowerCase()).includes(v)) return false;
  return null;
}

function getSlaBreachedFlag(ticket, metric) {
  const policyMetrics = Array.isArray(ticket.slas?.policy_metrics)
    ? ticket.slas.policy_metrics : [];
  if (!policyMetrics.length) return null;

  const solvedAt = metric?.solved_at ? new Date(metric.solved_at) : null;

  return policyMetrics.some(m => {
    if (!m.breach_at) return false;
    if (solvedAt) {
      return new Date(m.breach_at) < solvedAt;
    }
    return m.stage === 'breached';
  });
}

const rows = tickets.map(ticket => {
  const metric = metricsByTicketId[String(ticket.id)] || {};
  const resolution = metric.full_resolution_time_in_minutes?.business ?? null;

  const articleLinkedRaw = getCustomFieldValue(ticket, ARTICLE_LINKED_FIELD_IDS);
  let articleLinkedFlag = normalizeBoolean(
    articleLinkedRaw,
    ['kcs_linked_yes', 'kcslinked_yes'],
    ['kcs_linked_no', 'kcslinked_no']
  );
  if (articleLinkedFlag == null) {
    if (hasAnyTag(ticket, ['kcs_linked_yes', 'kcslinked_yes'])) {
      articleLinkedFlag = true;
    } else if (hasAnyTag(ticket, ['kcs_linked_no', 'kcslinked_no'])) {
      articleLinkedFlag = false;
    }
  }

  return {
    ticket_id: ticket.id ?? null,
    ticket_created_at: ticket.created_at ?? null,
    ticket_updated_at: ticket.updated_at ?? null,
    ticket_solved_at: metric.solved_at ?? ticket.solved_at ?? null,
    status: ticket.status ?? null,
    channel: ticket.via?.channel ?? null,
    form_id: ticket.ticket_form_id ?? null,
    form_name: formName,
    assignee_id: ticket.assignee_id ?? null,
    group_id: ticket.group_id ?? null,
    csat_score: ticket.satisfaction_rating?.score ?? null,
    first_reply_time_business_minutes: metric.reply_time_in_minutes?.business ?? null,
    next_reply_time_business_minutes: null,
    pausable_update_time_business_minutes: metric.on_hold_time_in_minutes?.business ?? null,
    requester_wait_time_business_minutes: metric.requester_wait_time_in_minutes?.business ?? null,
    full_resolution_time_business_minutes: resolution,
    one_business_day_solve_flag: resolution != null ? resolution <= 480 : null,
    sla_breached_flag: getSlaBreachedFlag(ticket, metric),
    article_linked_flag: articleLinkedFlag,
    missed_call_flag: null,
    ticket_count: 1
  };
}).filter(row => row.ticket_id != null);

return [{
  json: {
    run_id: batch.run_id || null,
    current_batch: Number(batch.current_batch || 0),
    total_batches: Number(batch.total_batches || 0),
    expected_count: Number(batch.expected_count || rows.length),
    ticket_rows_json: JSON.stringify(rows),
    ticket_count: rows.length,
    input_rows: rows.length,
    batch_count: rows.length,
    next_page_url: batch.next_page_url || null,
    end_of_stream: batch.end_of_stream === true
  }
}];

const results = Array.isArray($json.results) ? $json.results : [];

return [{
  json: {
    ticket_ids: results.map(r => r.id).filter(id => id != null)
  }
}];

const fields = Array.isArray($json.ticket_fields) ? $json.ticket_fields : [];

return fields.map(f => ({
  json: {
    id: f.id,
    title: f.title,
    type: f.type,
    tag: f.tag ?? null,
    active: f.active,
    required: f.required ?? null,
    custom_field_options: Array.isArray(f.custom_field_options)
      ? f.custom_field_options.map(o => ({
          name: o.name,
          value: o.value,
          default: o.default ?? false
        }))
      : null
  }
}));

const data = $getWorkflowStaticData('global');
const row = $json || {};

data.sync_pages_loaded = (data.sync_pages_loaded || 0) + 1;

data.sync_input_rows = (data.sync_input_rows || 0) + Number(row.parsed_rows || row.input_rows || 0);

data.sync_upserted_rows = (data.sync_upserted_rows || 0) + Number(row.upserted_rows || 0);

return [{
  json: {
    input_rows: Number(row.input_rows || 0),
    upserted_rows: Number(row.upserted_rows || 0),
    batch_count: Number(row.batch_count || 0),
    end_of_stream: row.end_of_stream === true,
    next_page_url: row.next_page_url || null
  }
}];

const BATCH_SIZE = 100;

const ids = $input.all()
  .map(item => item.json.ticket_id)
  .filter(id => id !== null && id !== undefined);

const runId = $('Code - Parse Backfill Params').first().json.run_id;
const totalBatches = Math.ceil(ids.length / BATCH_SIZE);
const batches = [];

for (let i = 0; i < ids.length; i += BATCH_SIZE) {
  const batchIds = ids.slice(i, i + BATCH_SIZE);
  batches.push({
    json: {
      run_id: runId,
      batch_number: Math.floor(i / BATCH_SIZE) + 1,
      total_batches: totalBatches,
      batch_size: batchIds.length,
      ids_csv: batchIds.join(',')
    }
  });
}

return batches;

const ticketBatch = $('HTTP: Fetch Ticket Batch with SLAs').first().json || {};
const tickets = Array.isArray(ticketBatch.tickets) ? ticketBatch.tickets : [];
const batch = $('Loop Over SLA Batches').first().json || {};

function getSlaBreachedFlag(ticket) {
  const policyMetrics = Array.isArray(ticket.slas?.policy_metrics)
    ? ticket.slas.policy_metrics : [];
  if (!policyMetrics.length) return null;

  const isClosed = ticket.status === 'closed' || ticket.status === 'solved';
  const updatedAt = ticket.updated_at ? new Date(ticket.updated_at) : null;

  return policyMetrics.some(m => {
    if (!m.breach_at) return false;
    if (isClosed && updatedAt) {
      return new Date(m.breach_at) < updatedAt;
    }
    return m.stage === 'breached';
  });
}

const rows = tickets
  .filter(ticket => ticket.id != null)
  .map(ticket => ({
    ticket_id: ticket.id,
    sla_breached_flag: getSlaBreachedFlag(ticket)
  }));

return [{
  json: {
    run_id: batch.run_id || null,
    batch_number: Number(batch.batch_number || 0),
    total_batches: Number(batch.total_batches || 0),
    batch_size: Number(batch.batch_size || 0),
    ticket_rows_json: JSON.stringify(rows),
    row_count: rows.length
  }
}];

const body = $json.body || {};

if (!body.date_from || !body.date_to) {
  throw new Error('date_from and date_to are required');
}

return [{
  json: {
    run_id: body.run_id || `sla-backfill-${new Date().toISOString().replace(/[:.]/g, '-')}`,
    date_from: body.date_from,
    date_to: body.date_to
  }
}];

const tickets = $json.results || [];

if (tickets.length === 0) {
  return [{ json: { error: 'no tickets found' } }];
}

const tagFrequency = {};
const customFieldSummary = {};
const kaTags = new Set();

for (const ticket of tickets) {
  // Check tags - Zendesk Knowledge Capture stores linked articles as ka_ARTICLEID tags
  const tags = ticket.tags || [];
  for (const tag of tags) {
    tagFrequency[tag] = (tagFrequency[tag] || 0) + 1;
    if (tag.startsWith('ka_')) kaTags.add(tag);
  }

  // Check custom fields for any non-null values we haven't mapped yet
  const fields = ticket.custom_fields || [];
  for (const f of fields) {
    if (f.value !== null && f.value !== '' && f.value !== false) {
      if (!customFieldSummary[f.id]) {
        customFieldSummary[f.id] = {
          field_id: f.id,
          sample_values: new Set()
        };
      }
      customFieldSummary[f.id].sample_values.add(String(f.value).slice(0, 80));
    }
  }
}

// Identify any tags that look like KB/article references
const articleRelatedTags = Object.entries(tagFrequency)
  .filter(([tag]) =>
    tag.startsWith('ka_') ||
    tag.includes('kb_') ||
    tag.includes('article') ||
    tag.includes('knowledge')
  )
  .map(([tag, count]) => ({ tag, count }))
  .sort((a, b) => b.count - a.count);

// Serialize custom field summary
const fieldList = Object.values(customFieldSummary).map(f => ({
  field_id: f.field_id,
  sample_values: [...f.sample_values].slice(0, 3)
}));

return [{
  json: {
    tickets_sampled: tickets.length,
    ka_tags_found: [...kaTags],
    article_related_tags: articleRelatedTags,
    all_custom_fields_with_values: fieldList,
    note: 'ka_ tags = Knowledge Capture article links. Check article_related_tags first.'
  }
}];
